import * as SecureStore from 'expo-secure-store';

async function storeToken(token) {
  try {
    await SecureStore.setItemAsync('authToken', token);
    console.log('Token stocké avec succès');
  } catch (error) {
    console.error('Erreur lors du stockage du token:', error);
  }
}

async function getToken() {
  try {
    const token = await SecureStore.getItemAsync('authToken');
    return token;
  } catch (error) {
    console.error('Erreur lors de la récupération du token:', error);
    return null;
  }
}

async function deleteToken() {
  try {
    await SecureStore.deleteItemAsync('authToken');
    console.log('Token supprimé avec succès');
  } catch (error) {
    console.error('Erreur lors de la suppression du token:', error);
  }
}

import * as SecureStore from 'expo-secure-store';
import AsyncStorage from '@react-native-async-storage/async-storage';

async function clearAllUserData() {
  try {
    // 1. Supprimer le token de SecureStore
    await SecureStore.deleteItemAsync('authToken');

    // 2. Supprimer les informations utilisateur de SecureStore
    await SecureStore.deleteItemAsync('userEmail');
    await SecureStore.deleteItemAsync('userName');

    // 3. Supprimer les préférences utilisateur d'AsyncStorage
    const keys = await AsyncStorage.getAllKeys();
    const userPrefKeys = keys.filter(key => 
      key.startsWith('user_') || 
      key === 'theme' || 
      key === 'notifications'
    );
    await AsyncStorage.multiRemove(userPrefKeys);

    console.log('Toutes les données utilisateur ont été effacées');
  } catch (error) {
    console.error('Erreur lors du nettoyage des données:', error);
  }
}

import { create } from 'zustand';
import * as SecureStore from 'expo-secure-store';

const TOKEN_KEY = 'authToken';

const useAuthStore = create((set, get) => ({
  token: null,
  user: null,
  isLoading: true,

  // Initialisation : charger le token depuis SecureStore
  init: async () => {
    try {
      const storedToken = await SecureStore.getItemAsync(TOKEN_KEY);
      if (storedToken) {
        // Optionnel : valider le token avec l'API
        set({ token: storedToken, isLoading: false });
      } else {
        set({ isLoading: false });
      }
    } catch (error) {
      console.error('Erreur lors du chargement du token:', error);
      set({ isLoading: false });
    }
  },

  // Connexion
  login: async (userData, token) => {
    try {
      // Stocker dans SecureStore
      await SecureStore.setItemAsync(TOKEN_KEY, token);
      // Mettre à jour le store
      set({ token, user: userData });
      return { success: true };
    } catch (error) {
      console.error('Erreur lors de la connexion:', error);
      return { success: false, error: error.message };
    }
  },

  // Déconnexion
  logout: async () => {
    try {
      // Supprimer de SecureStore
      await SecureStore.deleteItemAsync(TOKEN_KEY);
      // Vider le store
      set({ token: null, user: null });
      return { success: true };
    } catch (error) {
      console.error('Erreur lors de la déconnexion:', error);
      return { success: false, error: error.message };
    }
  },

  // Vérifier si l'utilisateur est connecté
  isAuthenticated: () => {
    return get().token !== null;
  },
}));

