import * as SecureStore from 'expo-secure-store';
import AsyncStorage from '@react-native-async-storage/async-storage';

const FIRST_LAUNCH_KEY = '@first_launch';

async function handleFirstLaunch() {
  const hasLaunched = await AsyncStorage.getItem(FIRST_LAUNCH_KEY);

  if (hasLaunched === null) {
    // Première installation
    await SecureStore.deleteItemAsync('authToken');
    await SecureStore.deleteItemAsync('userEmail');
    await AsyncStorage.setItem(FIRST_LAUNCH_KEY, 'true');
    console.log('Nettoyage des tokens orphelins effectué');
    return true; // Première installation
  }

  return false; // Lancement normal
}
```

Sur iOS, SecureStore utilise le Keychain. Aucune configuration supplémentaire n'est généralement nécessaire pour un projet Expo classique. Cependant, si vous utilisez 'keychainService' ou 'requireAuthentication', vous devez activer le 'Keychain Sharing' dans Xcode (Capabilities). Pour EAS Build, cela se configure via app.json :
```json
{
  "expo": {
    "ios": {
      "entitlements": {
        "keychain-access-groups": ["$(AppIdentifierPrefix)com.monapp"]
      }
    }
  }
}
