import { useEffect } from 'react';
import * as SecureStore from 'expo-secure-store';
import { AppState } from 'react-native';
import useAuthStore from './stores/authStore';

const INACTIVITY_LIMIT = 30 * 60 * 1000; // 30 minutes en millisecondes
const LAST_ACTIVITY_KEY = 'lastActivityTimestamp';

export function useAutoLogout() {
  const { logout, isAuthenticated } = useAuthStore();

  // Mettre à jour le timestamp de la dernière activité
  const updateLastActivity = async () => {
    if (!isAuthenticated()) return;
    const timestamp = Date.now();
    await SecureStore.setItemAsync(LAST_ACTIVITY_KEY, timestamp.toString());
  };

  // Vérifier l'inactivité
  useEffect(() => {
    let interval: NodeJS.Timeout;

    const checkInactivity = async () => {
      if (!isAuthenticated()) return;

      const lastActivityStr = await SecureStore.getItemAsync(LAST_ACTIVITY_KEY);
      if (!lastActivityStr) return;

      const lastActivity = parseInt(lastActivityStr, 10);
      const now = Date.now();

      if (now - lastActivity > INACTIVITY_LIMIT) {
        console.log('Déconnexion automatique pour inactivité');
        await logout();
        // Optionnel : afficher une alerte à l'utilisateur
      }
    };

    // Vérifier toutes les minutes
    interval = setInterval(checkInactivity, 60 * 1000);

    return () => clearInterval(interval);
  }, [isAuthenticated, logout]);

  // Surveiller les interactions utilisateur
  useEffect(() => {
    const events = ['mousedown', 'keydown', 'touchstart', 'scroll'];

    const handleUserInteraction = () => {
      updateLastActivity();
    };

    events.forEach(event => {
      window.addEventListener(event, handleUserInteraction);
    });

    // Pour React Native, utiliser AppState
    const subscription = AppState.addEventListener('change', (nextAppState) => {
      if (nextAppState === 'active') {
        updateLastActivity();
      }
    });

    return () => {
      events.forEach(event => {
        window.removeEventListener(event, handleUserInteraction);
      });
      subscription.remove();
    };
  }, []);

  // Initialiser le timestamp au premier rendu
  useEffect(() => {
    if (isAuthenticated()) {
      updateLastActivity();
    }
  }, [isAuthenticated]);
}
